from typing import Dict
from collections import deque
import random


class OldestUniqueTracker:
    def __init__(self) -> None:
        self._counts: Dict[int, int] = {}
        # Python dict preserves insertion order, so the first key is the
        # oldest currently-unique id. Delete-by-key is O(1).
        self._unique: Dict[int, None] = {}

    def submitItem(self, id: int) -> None:
        self._counts[id] = self._counts.get(id, 0) + 1
        freq = self._counts[id]
        if freq == 1:
            self._unique[id] = None          # first sighting -> candidate
        elif freq == 2:
            self._unique.pop(id, None)        # became duplicate -> evict by key

    def consumeOldestUnique(self) -> int:
        if not self._unique:
            return -1
        oldest = next(iter(self._unique))     # O(1) peek of oldest key
        del self._unique[oldest]
        return oldest


# ---- Brute-force oracle ----
class BruteTracker:
    def __init__(self) -> None:
        self.stream = deque()
        self.counts = {}
        self.consumed = set()

    def submitItem(self, id: int) -> None:
        self.stream.append(id)
        self.counts[id] = self.counts.get(id, 0) + 1

    def consumeOldestUnique(self) -> int:
        for x in self.stream:
            if self.counts[x] == 1 and x not in self.consumed:
                self.consumed.add(x)
                return x
        return -1


def run(ops, tracker_cls):
    t = tracker_cls()
    out = []
    for op in ops:
        if op[0] == 's':
            t.submitItem(op[1])
        else:
            out.append(t.consumeOldestUnique())
    return out


# Example 1
ops1 = [('s',4),('s',2),('s',5),('s',1),('s',2),('c',)]
print("ex1:", run(ops1, OldestUniqueTracker))   # expect [4]

# Example 2
ops2 = [('s',4),('s',2),('s',5),('s',1),('s',2),('s',4),('c',)]
print("ex2:", run(ops2, OldestUniqueTracker))   # expect [5]

# Edge: consume on empty
print("empty:", run([('c',)], OldestUniqueTracker))  # [-1]

# Edge: consume then resubmit same id (assumption: count persists)
print("resub:", run([('s',7),('c',),('s',7),('c',)], OldestUniqueTracker))  # [7, -1]

# Randomized stress vs brute oracle
random.seed(1)
mismatch = 0
for _ in range(3000):
    ops = []
    for _ in range(random.randint(0, 30)):
        if random.random() < 0.65:
            ops.append(('s', random.randint(0, 6)))
        else:
            ops.append(('c',))
    if run(ops, OldestUniqueTracker) != run(ops, BruteTracker):
        mismatch += 1
print("mismatches:", mismatch)
